module tb_alu;
  logic signed [31:0] tb_src_a;
  logic signed [31:0] tb_src_b;
  logic [3:0] tb_control;
  logic tb_zero;
  logic [31:0] tb_result;
  string dumpfile;

  Alu TestALU(.src_a(tb_src_a), .src_b(tb_src_b), .alu_control(tb_control),
  .zero(tb_zero), .alu_result(tb_result));
  
  initial begin
    // for waveform analysis
    $value$plusargs("DUMPFILE=%s", dumpfile);
    $dumpfile(dumpfile);
    $dumpvars();

  // ─────────────────────────────────────────────
  //  Generated by Claude Sonnet 4.6
  // ─────────────────────────────────────────────

  // ADDITION – overflow: MAX_UINT + 1 wraps to 0
  tb_src_a = 32'hFFFF_FFFF;
  tb_src_b = 32'h0000_0001;
  tb_control = 4'b0000;
  #10;
  assert (tb_result == 32'h0000_0000)
    else $fatal(1, "ADDITION overflow failed, got %b with %b & %b",
                tb_result, tb_src_a, tb_src_b);

  // SUBTRACTION – underflow: 0 - 1 wraps to MAX_UINT
  tb_src_a = 32'h0000_0000;
  tb_src_b = 32'h0000_0001;
  tb_control = 4'b0001;
  #10;
  assert (tb_result == 32'hFFFF_FFFF)
    else $fatal(1, "SUBTRACTION underflow failed, got %b with %b & %b",
                tb_result, tb_src_a, tb_src_b);

  // AND – all-ones & all-zeros = all-zeros
  tb_src_a = 32'hFFFF_FFFF;
  tb_src_b = 32'h0000_0000;
  tb_control = 4'b0010;
  #10;
  assert (tb_result == 32'h0000_0000)
    else $fatal(1, "AND all-ones/all-zeros failed, got %b with %b & %b",
                tb_result, tb_src_a, tb_src_b);

  // OR – all-zeros | all-zeros = all-zeros
  tb_src_a = 32'h0000_0000;
  tb_src_b = 32'h0000_0000;
  tb_control = 4'b0011;
  #10;
  assert (tb_result == 32'h0000_0000)
    else $fatal(1, "OR all-zeros failed, got %b with %b & %b",
                tb_result, tb_src_a, tb_src_b);

  // SLT – signed: MIN_INT < 0 should be true (1)
  tb_src_a = 32'h8000_0000; // most negative signed value
  tb_src_b = 32'h0000_0000;
  tb_control = 4'b0101;
  #10;
  assert (tb_result == 32'h0000_0001)
    else $fatal(1, "SLT min-signed failed, got %b with %b & %b",
                tb_result, tb_src_a, tb_src_b);

  // XOR – all-ones ^ all-ones = all-zeros
  tb_src_a = 32'hFFFF_FFFF;
  tb_src_b = 32'hFFFF_FFFF;
  tb_control = 4'b0100;
  #10;
  assert (tb_result == 32'h0000_0000)
    else $fatal(1, "XOR all-ones failed, got %b with %b & %b",
                tb_result, tb_src_a, tb_src_b);

  // SLTU – unsigned: 0 < MAX_UINT should be true (1)
  tb_src_a = 32'h0000_0000;
  tb_src_b = 32'hFFFF_FFFF;
  tb_control = 4'b0110;
  #10;
  assert (tb_result == 32'h0000_0001)
    else $fatal(1, "SLTU zero vs max failed, got %b with %b & %b",
                tb_result, tb_src_a, tb_src_b);

  // SLL – shift all-ones left by 1: MSB drops, LSB becomes 0
  tb_src_a = 32'hFFFF_FFFF;
  tb_src_b = 32'h0000_0001;
  tb_control = 4'b0111;
  #10;
  assert (tb_result == 32'hFFFF_FFFE)
    else $fatal(1, "SLL all-ones failed, got %b with %b & %b",
                tb_result, tb_src_a, tb_src_b);

  // SRL – shift all-ones right by 1: LSB drops, MSB becomes 0
  tb_src_a = 32'hFFFF_FFFF;
  tb_src_b = 32'h0000_0001;
  tb_control = 4'b1000;
  #10;
  assert (tb_result == 32'h7FFF_FFFF)
    else $fatal(1, "SRL all-ones failed, got %b with %b & %b",
                tb_result, tb_src_a, tb_src_b);

  // SRA – arithmetic shift: sign bit (1) must be replicated
  tb_src_a = 32'h8000_0000; // most negative, MSB=1
  tb_src_b = 32'h0000_0001;
  tb_control = 4'b1001;
  #10;
  assert (tb_result == 32'hC000_0000)
    else $fatal(1, "SRA sign-extension failed, got %b with %b & %b",
                tb_result, tb_src_a, tb_src_b);

  end
  
endmodule